BEGIN;

UPDATE blog_translations
SET
  content_html = regexp_replace(
    regexp_replace(
      content_html,
      '<hr><h2>Table of Contents</h2><ol>.*</ol><hr><h2>سنگ مرمریت چیست؟</h2>',
      '<hr><h2>اگر عجله دارید، مرمریت برای چه کاربردی مناسب است؟</h2><p>اگر زمان کمی دارید، مرمریت را بیشتر برای کف داخلی، پله داخلی، لابی، دیوار داخلی و فضاهای مسکونی یا تجاری سرپوشیده بررسی کنید. برای فضای بیرونی، سرویس مرطوب، کانتر آشپزخانه یا کف بسیار پرتردد، انتخاب نهایی باید با توجه به نوع سنگ، ضخامت، فرآوری، جذب آب، اقلیم و روش نگهداری انجام شود.</p><ul><li><p>برای کف و لابی روشن، مرمریت‌های کرم و روشن معمولاً انتخاب‌های رایجی هستند.</p></li><li><p>برای دیوار شاخص یا طراحی لوکس، مرمریت‌های تیره، رگه‌دار یا اسلب‌های بزرگ جلوه بیشتری دارند.</p></li><li><p>برای خرید پروژه‌ای، قبل از قیمت گرفتن حتماً سورت، ضخامت، ابعاد، متراژ، نوع فرآوری و شهر پروژه را مشخص کنید.</p></li></ul><hr><h2>سنگ مرمریت چیست؟</h2>'
    ),
    '<h3>۹. قیمت سنگ مرمریت</h3><p>قیمت سنگ مرمریت به عوامل مختلفی بستگی دارد؛ از جمله نوع معدن، سورت، رنگ، ابعاد، ضخامت، کیفیت فرآوری، میزان تقاضا، هزینه حمل و شرایط بازار. بنابراین بهتر است قیمت روز مرمریت بر اساس نمونه واقعی و مشخصات پروژه استعلام شود، نه فقط بر اساس نام سنگ.</p><p>برای بررسی قیمت روز، موجودی، ابعاد قابل تأمین و انتخاب سنگ مناسب پروژه می‌توانید با تیم سنگ حسن تماس بگیرید: <a target="_blank" rel="nofollow noopener" href="/about">تماس با سنگ حسن برای استعلام قیمت</a></p>',
    '<h3>۹. قیمت سنگ مرمریت</h3><p>قیمت سنگ مرمریت فقط به نام سنگ وابسته نیست. دو سنگ با نام یکسان، اگر از نظر معدن، سورت، ضخامت، ابعاد یا کیفیت فرآوری متفاوت باشند، می‌توانند قیمت متفاوتی داشته باشند. برای همین قیمت روز مرمریت باید بر اساس نمونه واقعی و مشخصات پروژه استعلام شود.</p><table><tbody><tr><th colspan="1" rowspan="1"><p>عامل مؤثر بر قیمت</p></th><th colspan="1" rowspan="1"><p>چه زمانی قیمت بالاتر می‌رود؟</p></th></tr><tr><td colspan="1" rowspan="1"><p>معدن و نام تجاری</p></td><td colspan="1" rowspan="1"><p>مرمریت‌های شناخته‌شده‌تر، کمیاب‌تر یا پرتقاضاتر معمولاً قیمت بالاتری دارند.</p></td></tr><tr><td colspan="1" rowspan="1"><p>سورت و یکنواختی</p></td><td colspan="1" rowspan="1"><p>هرچه رنگ، رگه، سلامت و یکدستی بچ بهتر باشد، ارزش سنگ بیشتر می‌شود.</p></td></tr><tr><td colspan="1" rowspan="1"><p>ابعاد پلاک یا اسلب</p></td><td colspan="1" rowspan="1"><p>ابعاد بزرگ‌تر، اسلب سالم‌تر و برش دقیق‌تر معمولاً هزینه بیشتری دارد.</p></td></tr><tr><td colspan="1" rowspan="1"><p>ضخامت</p></td><td colspan="1" rowspan="1"><p>ضخامت بالاتر وزن، مصرف کوپ و هزینه حمل و نصب را افزایش می‌دهد.</p></td></tr><tr><td colspan="1" rowspan="1"><p>نوع فرآوری</p></td><td colspan="1" rowspan="1"><p>صیقلی، هوند، چرمی، تیشه‌ای یا بوش‌همر هرکدام هزینه تولید و کاربرد متفاوت دارند.</p></td></tr><tr><td colspan="1" rowspan="1"><p>مقدار سفارش</p></td><td colspan="1" rowspan="1"><p>در پروژه‌های بزرگ، یکدستی بچ و امکان تأمین کامل روی قیمت نهایی اثر دارد.</p></td></tr><tr><td colspan="1" rowspan="1"><p>حمل و شهر پروژه</p></td><td colspan="1" rowspan="1"><p>فاصله، نوع بسته‌بندی، وزن بار و شرایط تخلیه در هزینه تمام‌شده اثرگذار است.</p></td></tr></tbody></table><p>برای استعلام دقیق قیمت روز مرمریت، بهتر است این اطلاعات را آماده کنید: نوع سنگ یا معدن، ابعاد پلاک یا اسلب، متراژ یا تعداد، ضخامت، نوع فرآوری، شهر پروژه و زمان تقریبی تحویل.</p><p>برای بررسی قیمت روز، موجودی، ابعاد قابل تأمین و انتخاب سنگ مناسب پروژه می‌توانید مشخصات پروژه را برای تیم سنگ حسن ارسال کنید: <a target="_blank" rel="nofollow noopener" href="/about">ارسال مشخصات پروژه و استعلام قیمت مرمریت</a></p>'
  ),
  content_json = '{"type":"doc","content":[]}'::jsonb,
  updated_at = NOW()
WHERE locale = 'fa'
  AND slug = 'everything-about-marble-stone';

COMMIT;
